/* *********** ADMIN *********** */
VAR _admin = 
	CALCULATE(
		DIVIDE(
			SUM('fact_Metrics'[Sick_Leave_Day_Without_Pregnancy]),
			SUMX(
				'fact_Metrics',
				'fact_Metrics'[FTE_WEIGHTED_WORK_DAY_FOR_ABSENTEEISM] + 'fact_Metrics'[Sick_Leave_Day_Without_Pregnancy]
			)
		)
	)

/* *********** LT *********** */
VAR _admin_lt =
	CALCULATE(
		DIVIDE(
			SUM('fact_Metrics'[Sick_Leave_Day_Without_Pregnancy]),
			SUMX(
				'fact_Metrics',
				'fact_Metrics'[FTE_WEIGHTED_WORK_DAY_FOR_ABSENTEEISM] + 'fact_Metrics'[Sick_Leave_Day_Without_Pregnancy]
			)
		),
		REMOVEFILTERS('fact_Metrics'),
		_filter_lt
	)
VAR _res =
	SWITCH (
		_roleIndex,
		0, _admin_lt,    -- LT
		1, _admin,       -- Admin
		_admin
	)

RETURN COALESCE(_res, 0)
